CommonData.BannerCustomCSS:
#onetrust-consent-sdk {
  font-family: "Ubuntu";
}

#onetrust-pc-sdk .ot-switch-nob:before {
  background-color: white !important;
}

.ot-switch-nob {
  background-color: #e5e5e5 !important;
}

.ot-switch-nob:hover {
  background-color: #d9d9d9 !important;
}

.ot-switch-nob:focus {
  background-color: #e5e5e5 !important;
}

.ot-switch {
  border-radius: 16px !important;
  outline: none !important;
}

.ot-switch:focus {
  box-shadow: 0 0 0 3px white, 0 0 0 5px #0970e6 !important;
}

input:checked + .ot-switch .ot-switch-nob {
  background-color: #0970e6 !important;
}

input:checked + .ot-switch .ot-switch-nob:hover {
  background-color: #0863cc !important;
}

#onetrust-banner-sdk,
#onetrust-pc-sdk {
  width: 500px !important;
  border-radius: 6px !important;
  max-width: unset !important;
  min-width: unset !important;
  overflow: unset !important;
  height: auto !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
  margin-top: 0 !important;
  max-height: 100% !important;
  position: relative;
}

#onetrust-pc-sdk #ot-pc-content,
#onetrust-group-container {
  margin: 0 !important;
  width: auto !important;
  position: static !important;
  padding: 0 !important;
  height: auto;
  overflow-y: auto !important;
  // margin-bottom: 88px !important;
  box-sizing: border-box !important;
  padding: 16px !important;
  // max-height: calc(100vh - 88px) !important;
}

#onetrust-pc-sdk .ot-pc-footer,
#onetrust-button-group-parent {
  padding: 16px;
  box-sizing: border-box;
  background-color: white;
  max-height: unset !important;
  left: 0;
  border: 0;
  border-radius: 6px !important;
}

.ot-btn-container {
  .save-preference-btn-handler {
    order: 2;
  }

  .ot-pc-refuse-all-handler {
    order: 1;
  }
  #accept-recommended-btn-handler {
    order: 3;
  }
}
@media (max-width: 599.99px) {
  .save-preference-btn-handler {
    order: 2 !important;
  }

  .ot-pc-refuse-all-handler {
    order: 3 !important;
  }
  #accept-recommended-btn-handler {
    order: 1 !important;
  }
}

#accept-recommended-btn-handler {
  // order: 1 !important;
}

.ot-pc-header {
  display: none;
}

#onetrust-policy-title,
#onetrust-policy-text {
  margin: 0 !important;
}

#onetrust-policy-text a {
  margin: 20px 0 0 !important;
  display: block;
  padding: 0;
  text-decoration: underline !important;
  font-weight: 400 !important;
}

#onetrust-consent-sdk a:focus {
  outline: none !important;
}

#onetrust-banner-sdk #onetrust-policy {
  margin: 0;
}

#onetrust-button-group button,
.ot-btn-container button,
#ot-pc-content > button {
  flex: 1 0 auto;
  // width: 123px !important;
  height: 40px !important;
  margin: 0 !important;
  font-size: 16px !important;
  font-weight: 700 !important;
  line-height: normal !important;
  padding: 0 !important;
  text-decoration: none !important;
  border-radius: 4px !important;
  letter-spacing: normal !important;
  display: inline-block !important;
  width: 150px !important;
}

@media (max-width: 599.99px) {
  #onetrust-button-group button,
  .ot-btn-container button,
  #ot-pc-content > button {
    width: 100% !important;
  }

  #onetrust-reject-all-handler {
    order: 1;
  }
}

.banner-actions-container {
  max-width: none !important;
  order: 1;
}

.banner-actions-container button,
.ot-btn-container button,
#ot-pc-content > button {
  background-color: #416dd7 !important;
  color: white !important;
}

.banner-actions-container,
.ot-btn-container {
  display: flex !important;
  flex-direction: row;
  gap: 8px;
  // order: 1;
  float: unset;
}

@media (max-width: 599.99px) {
  .banner-actions-container {
    order: 0;
  }

  .banner-actions-container,
  .ot-btn-container {
    flex-direction: column;
  }
}

.ot-btn-container {
  margin: 0 !important;
  width: 100% !important;
}

#onetrust-banner-sdk #onetrust-button-group-parent {
  border-top: 1px solid #cfd8dc;
  border-radius: 0 !important;
}

#onetrust-pc-btn-handler,
.save-preference-btn-handler {
  display: block !important;
  float: unset !important;
  text-align: center !important;
  max-width: none !important;
  // width:100%;
}

// .ot-pc-refuse-all-handler,
// #accept-recommended-btn-handler {
//     background-color: white !important;
//     color: #416dd7 !important;
// }

#onetrust-button-group {
  display: flex !important;
  flex-direction: column;
  gap: 8px;
}

@media (min-width: 600px) {
  #onetrust-button-group {
    flex-direction: row;
  }
}

#onetrust-policy-text {
  font-size: 16px !important;
  font-family: Ubuntu !important;
  color: black !important;
  width: auto !important;
}

#onetrust-policy-text a {
  text-decoration: none;
}

#onetrust-policy-title {
  color: black !important;
  padding: 0 !important;
  margin-bottom: 20px !important;
  font-size: 20px !important;
  font-weight: 700 !important;
  width: auto !important;
}

/*PC*/

.ot-pc-footer-logo,
.ot-pc-logo {
  display: none !important;
}

.ot-cat-header,
.ot-plus-mins {
  color: #416dd7 !important;
}

#onetrust-group-container {
  padding: 16px !important;
  max-height: calc(100vh - 168px) !important;
}

#onetrust-button-group-parent {
  padding: 16px !important;
}

